// ==================== Header Sanitizer / Security ====================

@Service
class HeaderSanitizer {

    // Allowed header key pattern: alphanumeric, hyphens, underscores, dots
    private static final Pattern ALLOWED_HEADER_KEY_PATTERN = Pattern.compile("^[a-zA-Z0-9._-]+$");

    // Maximum limits
    private static final int MAX_HEADER_KEY_LENGTH = 128;
    private static final int MAX_HEADER_VALUE_LENGTH = 1024;
    private static final int MAX_HEADERS_COUNT = 20;
    private static final int MAX_TOTAL_HEADERS_SIZE_BYTES = 8192; // 8KB total headers

    // Blocklist of header keys that should not be set by users (internal/system headers)
    private static final Set<String> BLOCKED_HEADER_KEYS = Set.of(
            "authorization",
            "cookie",
            "set-cookie",
            "x-internal-secret",
            "x-forwarded-for",
            "x-real-ip",
            "host",
            "connection",
            "proxy-authorization",
            "www-authenticate",
            "x-api-key",
            "password",
            "secret",
            "token",
            "credential",
            "private-key",
            "access-token",
            "refresh-token",
            "session-id",
            "csrf-token"
    );

    // Allowed topic pattern
    private static final Pattern ALLOWED_TOPIC_PATTERN = Pattern.compile("^[a-zA-Z0-9._-]+$");
    private static final Set<String> ALLOWED_TOPICS = Set.of(
            "event-tracking",
            "user-events",
            "system-events",
            "audit-events",
            "analytics-events"
    );

    /**
     * Sanitize and validate headers from user input.
     * Returns a clean map of validated headers.
     */
    public Map<String, String> sanitizeHeaders(Map<String, String> rawHeaders) {
        if (rawHeaders == null || rawHeaders.isEmpty()) {
            return Collections.emptyMap();
        }

        if (rawHeaders.size() > MAX_HEADERS_COUNT) {
            throw new HeaderValidationException(
                    String.format("Too many headers. Maximum allowed: %d, provided: %d",
                            MAX_HEADERS_COUNT, rawHeaders.size()));
        }

        Map<String, String> sanitized = new LinkedHashMap<>();
        int totalSizeBytes = 0;

        for (Map.Entry<String, String> entry : rawHeaders.entrySet()) {
            String key = entry.getKey();
            String value = entry.getValue();

            // Validate key
            validateHeaderKey(key);

            // Validate value
            String sanitizedValue = sanitizeHeaderValue(key, value);

            // Check blocked keys (case-insensitive)
            if (BLOCKED_HEADER_KEYS.contains(key.toLowerCase())) {
                throw new HeaderValidationException(
                        String.format("Header key '%s' is not allowed for security reasons", key));
            }

            // Track total size
            int entrySize = key.getBytes(StandardCharsets.UTF_8).length
                    + sanitizedValue.getBytes(StandardCharsets.UTF_8).length;
            totalSizeBytes += entrySize;

            if (totalSizeBytes > MAX_TOTAL_HEADERS_SIZE_BYTES) {
                throw new HeaderValidationException(
                        String.format("Total headers size exceeds maximum of %d bytes", MAX_TOTAL_HEADERS_SIZE_BYTES));
            }

            sanitized.put(key, sanitizedValue);
        }

        return Collections.unmodifiableMap(sanitized);
    }

    private void validateHeaderKey(String key) {
        if (key == null || key.isBlank()) {
            throw new HeaderValidationException("Header key must not be null or blank");
        }

        if (key.length() > MAX_HEADER_KEY_LENGTH) {
            throw new HeaderValidationException(
                    String.format("Header key '%s' exceeds maximum length of %d", key, MAX_HEADER_KEY_LENGTH));
        }

        if (!ALLOWED_HEADER_KEY_PATTERN.matcher(key).matches()) {
            throw new HeaderValidationException(
                    String.format("Header key '%s' contains invalid characters. Only alphanumeric, hyphens, underscores, and dots are allowed", key));
        }
    }

    private String sanitizeHeaderValue(String key, String value) {
        if (value == null) {
            return "";
        }

        // Trim whitespace
        String trimmed = value.trim();

        if (trimmed.length() > MAX_HEADER_VALUE_LENGTH) {
            throw new HeaderValidationException(
                    String.format("Header value for key '%s' exceeds maximum length of %d", key, MAX_HEADER_VALUE_LENGTH));
        }

        // Remove control characters (prevent injection attacks)
        String cleaned = trimmed.replaceAll("[\\x00-\\x1F\\x7F]", "");

        // Prevent CRLF injection
        cleaned = cleaned.replaceAll("[\r\n]", "");

        return cleaned;
    }

    /**
     * Validate and sanitize topic name.
     */
    public String sanitizeTopic(String topic) {
        if (topic == null || topic.isBlank()) {
            throw new TopicValidationException("Topic must not be null or blank");
        }

        String trimmed = topic.trim();

        if (!ALLOWED_TOPIC_PATTERN.matcher(trimmed).matches()) {
            throw new TopicValidationException(
                    String.format("Topic '%s' contains invalid characters", trimmed));
        }

        if (!ALLOWED_TOPICS.contains(trimmed)) {
            throw new TopicValidationException(
                    String.format("Topic '%s' is not in the allowed topics list: %s", trimmed, ALLOWED_TOPICS));
        }

        return trimmed;
    }

    /**
     * Sanitize message key.
     */
    public String sanitizeKey(String key) {
        if (key == null || key.isBlank()) {
            return null;
        }

        String trimmed = key.trim();
        // Remove control characters
        return trimmed.replaceAll("[\\x00-\\x1F\\x7F]", "");
    }

    /**
     * Sanitize message body - basic validation.
     */
    public String sanitizeMessage(String message) {
        if (message == null || message.isBlank()) {
            throw new MessageValidationException("Message must not be null or blank");
        }
        // Remove null bytes which could cause issues
        return message.replace("\0", "");
    }
}

