// ==================== Event Producer Service ====================

@Service
class EventProducerService {

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final HeaderSanitizer headerSanitizer;

    @Autowired
    public EventProducerService(KafkaTemplate<String, String> kafkaTemplate, HeaderSanitizer headerSanitizer) {
        this.kafkaTemplate = kafkaTemplate;
        this.headerSanitizer = headerSanitizer;
    }

    /**
     * Send an event message to Kafka with sanitized custom headers.
     */
    public CompletableFuture<EventResponse> sendEvent(String topic, String key, String message,
                                                       Map<String, String> customHeaders,
                                                       Map<String, String> httpHeaders) {

        // Sanitize all inputs
        String sanitizedTopic = headerSanitizer.sanitizeTopic(topic);
        String sanitizedKey = headerSanitizer.sanitizeKey(key);
        String sanitizedMessage = headerSanitizer.sanitizeMessage(message);
        Map<String, String> sanitizedCustomHeaders = headerSanitizer.sanitizeHeaders(customHeaders);

        // Generate a unique message ID for tracking
        String messageId = UUID.randomUUID().toString();

        // Create ProducerRecord
        ProducerRecord<String, String> record = new ProducerRecord<>(
                sanitizedTopic, null, sanitizedKey, sanitizedMessage);

        Headers headers = record.headers();

        // Add system headers (internal, not user-controlled)
        headers.add(new RecordHeader("x-message-id", messageId.getBytes(StandardCharsets.UTF_8)));
        headers.add(new RecordHeader("x-produced-at",
                Instant.now().toString().getBytes(StandardCharsets.UTF_8)));
        headers.add(new RecordHeader("x-producer", "event-tracking-api".getBytes(StandardCharsets.UTF_8)));

        // Add sanitized custom headers from request body
        Map<String, String> appliedHeaders = new LinkedHashMap<>();
        for (Map.Entry<String, String> entry : sanitizedCustomHeaders.entrySet()) {
            headers.add(new RecordHeader(entry.getKey(), entry.getValue().getBytes(StandardCharsets.UTF_8)));
            appliedHeaders.put(entry.getKey(), entry.getValue());
        }

        // Extract and add specific allowed HTTP headers (tracking-id, user-id, etc.)
        extractAndAddHttpHeaders(httpHeaders, headers, appliedHeaders);

        // Send the record
        CompletableFuture<SendResult<String, String>> future = kafkaTemplate.send(record);

        return future.thenApply(result -> {
            EventResponse response = new EventResponse();
            response.setStatus("SUCCESS");
            response.setMessageId(messageId);
            response.setTopic(result.getRecordMetadata().topic());
            response.setPartition(result.getRecordMetadata().partition());
            response.setOffset(result.getRecordMetadata().offset());
            response.setTimestamp(result.getRecordMetadata().timestamp());
            response.setAppliedHeaders(appliedHeaders);
            return response;
        });
    }

    /**
     * Extract specific allowed HTTP headers and add them to Kafka headers.
     * Only a whitelist of HTTP headers are forwarded.
     */
    private void extractAndAddHttpHeaders(Map<String, String> httpHeaders,
                                           Headers kafkaHeaders,
                                           Map<String, String> appliedHeaders) {
        if (httpHeaders == null || httpHeaders.isEmpty()) {
            return;
        }

        // Whitelist of HTTP headers that can be forwarded to Kafka
        Set<String> allowedHttpHeaders = Set.of(
                "x-tracking-id",
                "x-user-id",
                "x-correlation-id",
                "x-request-id",
                "x-session-id",
                "x-client-version",
                "x-device-type",
                "x-source-service",
                "x-tenant-id",
                "user-agent"
        );

        for (Map.Entry<String, String> entry : httpHeaders.entrySet()) {
            String headerKey = entry.getKey().toLowerCase();
            if (allowedHttpHeaders.contains(headerKey)) {
                String value = entry.getValue();
                if (value != null && !value.isBlank() && value.length() <= 1024) {
                    // Sanitize the value
                    String cleanValue = value.trim().replaceAll("[\\x00-\\x1F\\x7F]", "").replaceAll("[\r\n]", "");
                    String kafkaHeaderKey = "http-" + headerKey;
                    kafkaHeaders.add(new RecordHeader(kafkaHeaderKey, cleanValue.getBytes(StandardCharsets.UTF_8)));
                    appliedHeaders.put(kafkaHeaderKey, cleanValue);
                }
            }
        }
    }
}

// ==================== REST Controller ====================

@RestController
@RequestMapping("/api/v1/events")
class EventController {

    private final EventProducerService eventProducerService;

    @Autowired
    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    /**
     * POST /api/v1/events
     * Send an event to Kafka with custom headers.
     *
     * Request body:
     * {
     *   "topic": "event-tracking",
     *   "key": "user-123",
     *   "message": "{\"event\":\"page_view\",\"page\":\"/home\"}",
     *   "headers": {
     *     "tracking-id": "abc-123",
     *     "user-id": "user-456",
     *     "event-type": "page_view",
     *     "source": "web-app"
     *   }
     * }
     *
     * HTTP headers like X-Tracking-Id, X-User-Id, X-Correlation-Id are also captured.
     */
    @PostMapping
    public CompletableFuture<ResponseEntity<EventResponse>> sendEvent(
            @Valid @RequestBody EventRequest request,
            @RequestHeader Map<String, String> httpHeaders) {

        return eventProducerService.sendEvent(
                request.getTopic(),
                request.getKey(),
                request.getMessage(),
                request.getHeaders(),
                httpHeaders
        ).thenApply(response -> ResponseEntity.status(HttpStatus.CREATED).body(response));
    }

    /**
     * POST /api/v1/events/batch
     * Send multiple events in a batch.
     */
    @PostMapping("/batch")
    public CompletableFuture<ResponseEntity<List<EventResponse>>> sendBatchEvents(
            @Valid @RequestBody List<EventRequest> requests,
            @RequestHeader Map<String, String> httpHeaders) {

        if (requests.size() > 100) {
            throw new MessageValidationException("Batch size must not exceed 100 events");
        }

        List<CompletableFuture<EventResponse>> futures = requests.stream()
                .map(request -> eventProducerService.sendEvent(
                        request.getTopic(),
                        request.getKey(),
                        request.getMessage(),
                        request.getHeaders(),
                        httpHeaders
                ))
                .collect(Collectors.toList());

        CompletableFuture<Void> allOf = CompletableFuture.allOf(
                futures.toArray(new CompletableFuture[0]));

        return allOf.thenApply(v -> {
            List<EventResponse> responses = futures.stream()
                    .map(CompletableFuture::join)
                    .collect(Collectors.toList());
            return ResponseEntity.status(HttpStatus.CREATED).body(responses);
        });
    }

    // ==================== Exception Handlers ====================

    @ExceptionHandler(HeaderValidationException.class)
    public ResponseEntity<ErrorResponse> handleHeaderValidation(HeaderValidationException ex) {
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(new ErrorResponse("HEADER_VALIDATION_ERROR", ex.getMessage()));
    }

    @ExceptionHandler(TopicValidationException.class)
    public ResponseEntity<ErrorResponse> handleTopicValidation(TopicValidationException ex) {
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(new ErrorResponse("TOPIC_VALIDATION_ERROR", ex.getMessage()));
    }

    @ExceptionHandler(MessageValidationException.class)
    public ResponseEntity<ErrorResponse> handleMessageValidation(MessageValidationException ex) {
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(new ErrorResponse("MESSAGE_VALIDATION_ERROR", ex.getMessage()));
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ErrorResponse> handleGenericException(Exception ex) {
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(new ErrorResponse("INTERNAL_ERROR", "An unexpected error occurred"));
    }
}

